import React from "react"
import { Link } from "gatsby"
import styled from "styled-components"

type Props = {
  tags: [{
    fieldValue: string
    totalCount: number
  }]
}

const Ul = styled.ul`
margin: 10px 15px;
display: inline-block;
font-size: 1.2em;
`;

const Li = styled.li`
margin: 10px 15px;
display: inline-block;
font-size: 1.2em;
color: #8a8a8a;
`;

const Text = styled(Link)`
color: #8a8a8a;
font-size: .9em;
`

const Tags: React.FC<Props> = ({tags}) => {

  return (
      <Ul>
          {tags.map((tag) => (
            <Li key={tag.fieldValue}>
              <Text to={`/tags/${tag.fieldValue}/`}>
                {tag.fieldValue} ({tag.totalCount})
              </Text>
            </Li>
          ))}
      </Ul>
  )
}

export default Tags